package main

import "fmt"

func isPrime(number int) bool {
	if number < 2 {
		return false
	}

	for i := 2; i*i <= number; i++ {
		if number%i == 0 {
			return false
		}
	}
	return true
}

func main() {
	fmt.Println("1-50 arasindaki asal sayilar:")
	var primes []int

	for i := 1; i <= 50; i++ {
		if isPrime(i) {
			primes = append(primes, i)
		}
	}

	fmt.Println(primes)
	fmt.Println("\nToplam asal sayi adedi:", len(primes))

	// Tekil kontrol
	testNumber := 97
	fmt.Println("\n", testNumber, "asal mi:", isPrime(testNumber))

	testNumber = 100
	fmt.Println(testNumber, "asal mi:", isPrime(testNumber))
}
